# parse_packets_tester.py

import queue

from capture.parse_packets import PacketParser

# 创建测试队列
test_queue = queue.Queue()

# 添加测试数据包
test_packets = [
    "2024-01-15 14:30:25 | 192.168.1.100:54321 -> 192.168.1.1:80 | Length:45 | Data:29000000b0517009000000000000803f00000000000000000000803f000000000000000000000000ffffffff000000",
    "2024-01-15 14:30:26 | 192.168.1.100:54321 -> 192.168.1.1:80 | Length:1424 | Data:",
]

for packet in test_packets:
    test_queue.put(packet)

# 创建解析器并测试
parser = PacketParser()
parser.packet_queue = test_queue  # 替换为测试队列

print("开始测试解析器...")
parser.parse_packet()
parser.parse_packet()
